import React from 'react';

function Trade(props) {
    return(
        <div>
            {props.tradeList.id}
            <span className='buffer'></span>
            {props.tradeList.stock}
            <span className='buffer'></span>
            <span className='tradeTable-spacer'>{props.tradeList.method}</span>
            <span className='buffer'></span>
            {props.tradeList.quantity}
            <span className='buffer'></span>
            {props.trade.profitLoss}
            
        </div>
    )
}

export default Trade;
